from dataclasses import dataclass

@dataclass
class ValidationResult:
    passed: bool
    missing_fields: list[str]
    warnings: list[str]     # non-blocking but worth noting

def validate_request(req: DemandRequest) -> ValidationResult:
    missing = []
    warnings = []

    if not req.business_problem:
        missing.append("business_problem")
    if not req.success_definition:
        missing.append("success_definition")
    if not req.affected_process:
        missing.append("affected_process")
    if req.estimated_users <= 0:
        missing.append("estimated_users (must be > 0)")
    if not req.requesting_team:
        missing.append("requesting_team")
    if not req.requestor_email:
        missing.append("requestor_email")

    # Non-blocking warnings
    if req.expected_annual_value_usd is None:
        warnings.append("expected_annual_value_usd not provided; scoring will use defaults")
    if req.data_sensitivity == DataSensitivity.RESTRICTED and not req.regulatory_constraints:
        warnings.append("RESTRICTED data sensitivity: consider specifying regulatory_constraints")
    if req.desired_go_live and req.desired_go_live.year < 2026:
        warnings.append("desired_go_live is in the past; update or remove")

    return ValidationResult(passed=len(missing) == 0, missing_fields=missing, warnings=warnings)

def return_to_requestor(req: DemandRequest, result: ValidationResult) -> str:
    """Build the return email body for an incomplete submission."""
    req.status = IntakeStatus.RETURNED
    lines = [
        f"Your request {req.request_id} — '{req.affected_process}' — could not proceed to triage.",
        "",
        "Required fields missing:",
    ]
    for f in result.missing_fields:
        lines.append(f"  • {f}")
    if result.warnings:
        lines += ["", "Optional improvements:"]
        for w in result.warnings:
            lines.append(f"  ⚠ {w}")
    lines += ["", "Please re-submit once the above items are addressed."]
    return "\n".join(lines)
